<div class="input-component"><input class="input" v-if="type !== 'file'" v-bind="$attrs" :type="type" :value="modelValue" @input="$emit('update:modelValue', $event.target.value)"><input class="input" v-else-if="type === 'file'" v-bind="$attrs" :type="type" @change="$emit('handleChange', $event.target.files[0])"></div>